package main

import (
	"fmt"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest defines the structure for the incoming JSON payload
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the configuration and validation of a webhook URL.
// It receives a POST request, sends a test GET request to the provided URL with a 3s timeout,
// and returns the result as JSON.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	req := new(WebhookRequest)

	// Parse the JSON body into the struct
	if err := ctx.BodyParser(req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid request body",
		})
	}

	// Basic validation for the webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url is required",
		})
	}

	// Initialize an HTTP client with a strict 3-second timeout as required
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Validate the URL by sending a test GET request
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the endpoint returned a successful status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": fmt.Sprintf("Webhook URL returned non-success status code: %d", resp.StatusCode),
		})
	}

	// Logic to save the configuration would be implemented here
	// Example: database.SaveWebhook(req.WebhookURL)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configuration validated and saved successfully",
		"data": fiber.Map{
			"webhook_url": req.WebhookURL,
		},
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	fmt.Println("Server is running on :3000")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

