// WebhookRequest represents the incoming JSON body
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the standard JSON response
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles the configuration and validation of a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	req := new(WebhookRequest)

	// Parse JSON body
	if err := ctx.BodyParser(req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create a context with a 3-second timeout for the validation request
	timeoutCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Prepare the GET request
	httpReq, err := http.NewRequestWithContext(timeoutCtx, http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid URL format",
		})
	}

	// Execute the test request
	client := &http.Client{}
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(Response{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the status code is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(Response{
			Success: false,
			Message: "Webhook URL returned non-success status code",
		})
	}

	// In a real application, you would save the configuration to a database here.

	return ctx.Status(fiber.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configured and validated successfully",
	})
}

