import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest defines the expected JSON structure for the request body
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the registration and validation of a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	// Parse the JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid JSON body",
		})
	}

	// Basic validation of the input
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url field is required",
		})
	}

	// Create an HTTP client with a 3-second timeout requirement
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Validate the webhook URL by sending a GET request
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the status code is acceptable (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Webhook URL returned non-success status code",
			"code":    resp.StatusCode,
		})
	}

	// Logic to save the configuration would go here
	// For example: db.SaveWebhook(req.WebhookURL)

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configuration validated and saved successfully",
		"url":     req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Define the POST route
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

