type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// isUnsafeIP checks if an IP address belongs to a private, loopback, or local range.
// This is a critical check to prevent SSRF attacks.
func isUnsafeIP(ip net.IP) bool {
	return ip.IsLoopback() ||
		ip.IsLinkLocalUnicast() ||
		ip.IsLinkLocalMulticast() ||
		ip.IsInterfaceLocalMulticast() ||
		ip.IsUnspecified() ||
		ip.IsPrivate() // Requires Go 1.17+
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// SSRF Protection: Custom dialer to validate the resolved IP address.
	// The Control function is called after DNS resolution but before the connection is established.
	dialer := &net.Dialer{
		Timeout: 3 * time.Second,
		Control: func(network, address string, c syscall.RawConn) error {
			host, _, err := net.SplitHostPort(address)
			if err != nil {
				return err
			}
			ip := net.ParseIP(host)
			if ip == nil {
				return errors.New("invalid IP address")
			}
			if isUnsafeIP(ip) {
				return errors.New("access to internal or private network addresses is prohibited")
			}
			return nil
		},
	}

	// Create a custom HTTP client with SSRF protections
	client := &http.Client{
		Timeout: 5 * time.Second,
		Transport: &http.Transport{
			DialContext:           dialer.DialContext,
			ResponseHeaderTimeout: 3 * time.Second,
			DisableKeepAlives:     true, // Prevent connection reuse across different hosts
		},
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Do not follow redirects to prevent SSRF bypasses via 3xx responses
			return http.ErrUseLastResponse
		},
	}

	// Prepare the test request using GET method as required
	// We use the request context from Fiber for proper cancellation support
	testReq, err := http.NewRequestWithContext(ctx.Context(), "GET", req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to initialize test request",
		})
	}
	testReq.Header.Set("User-Agent", "Webhook-Validator/1.0")

	// Send test request to webhook URL
	resp, err := client.Do(testReq)
	if err != nil {
		// Return a generic error to avoid leaking details about the internal network
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL validation failed: unable to reach the provided URL or access denied",
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Route configuration
	app.Post("/api/webhook/configure", ConfigureWebhook)

	app.Listen(":3000")
}

