		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url is required",
		})
	}

	// Prepare the HTTP client with a mandatory 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Validate the webhook URL by sending a test GET request
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to validate webhook URL",
