	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configuration saved and validated",
		"data": fiber.Map{
			"webhook_url": req.WebhookURL,
			"http_status": resp.StatusCode,
		},
	})
}

func main() {
	app := fiber.New()

	// Route definition
	app.Post("/configure-webhook", ConfigureWebhook)

