// isReservedIP checks if an IP address is a loopback, private, link-local, or unspecified address.
// This is a key part of preventing SSRF attacks.
func isReservedIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
		return true
	}
	// IsPrivate reports whether ip is a private address according to RFC 1918 (IPv4) or RFC 4193 (IPv6).
	// Note: Requires Go 1.17+
	if ip.IsPrivate() {
		return true
	}
	return false
}

// ConfigureWebhook handles POST requests to configure a webhook URL.
// It validates the URL by sending a GET request and ensures the target is not an internal resource.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// SSRF Protection: Create a custom transport that validates the IP address before connecting.
	// This prevents the server from making requests to internal infrastructure or loopback.
	dialer := &net.Dialer{
		Timeout: 3 * time.Second,
	}

	transport := &http.Transport{
		DialContext: func(c context.Context, network, addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			// Resolve the hostname to IP addresses
			ips, err := net.DefaultResolver.LookupIP(c, "ip", host)
			if err != nil {
				return nil, err
			}

			// Check all resolved IPs; if any are public, we use the first public one.
			var targetIP net.IP
			for _, ip := range ips {
				if !isReservedIP(ip) {
					targetIP = ip
					break
				}
			}

			if targetIP == nil {
				return nil, errors.New("access to the requested host is forbidden (private or reserved IP)")
			}

			// Connect to the specific validated IP to prevent DNS rebinding attacks
			return dialer.DialContext(c, network, net.JoinHostPort(targetIP.String(), port))
		},
	}

	client := &http.Client{
		Transport: transport,
		Timeout:   5 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Do not follow redirects to prevent SSRF via redirection to internal IPs
			return http.ErrUseLastResponse
		},
	}

	// Send test request to webhook URL using GET method as requested
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) 

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	fmt.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

