}

// isSafeIP checks if an IP address is safe for outbound requests (not private or loopback)
func isSafeIP(ip net.IP) bool {
	if ip == nil {
		return false
	}
	// Check for loopback, link-local, unspecified, and private ranges (RFC 1918, RFC 4193)
	return !(ip.IsLoopback() || 
		ip.IsLinkLocalUnicast() || 
		ip.IsLinkLocalMulticast() || 
		ip.IsUnspecified() || 
		ip.IsPrivate())
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// 1. Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// 2. Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// 3. Validate URL format and scheme
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// 4. Create a secure HTTP client to prevent SSRF and DNS Rebinding
	// We use a custom DialContext to validate the IP address at connection time.
	client := &http.Client{
		Timeout: 5 * time.Second,
		Transport: &http.Transport{
			DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
				host, port, err := net.SplitHostPort(addr)
				if err != nil {
					return nil, err
				}

				// Resolve IPs for the host
				ips, err := net.LookupIP(host)
				if err != nil {
					return nil, err
				}

				// Validate all resolved IPs
				for _, ip := range ips {
					if !isSafeIP(ip) {
						return nil, errors.New("access to private or non-global IP addresses is prohibited")
					}
				}

				// To prevent DNS Rebinding, we dial the first validated IP specifically
				dialer := net.Dialer{Timeout: 3 * time.Second}
				return dialer.DialContext(ctx, network, net.JoinHostPort(ips[0].String(), port))
			},
		},
		// Disable redirects to prevent SSRF bypasses
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// 5. Send test request to webhook URL using GET method
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		// Return a generic error to avoid leaking internal network details
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to reach the webhook URL. Please ensure it is a public-facing URL.",
		})
	}
	defer resp.Body.Close()

	// 6. Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// 7. Save the configuration (Assume db logic is handled here)
	// db.SaveWebhookURL(req.WebhookURL)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()
	app.Post("/configure-webhook", ConfigureWebhook)
	app.Listen(":3000")
}

