// isUnsafeIP checks if an IP address is private, loopback, link-local, or otherwise internal.
func isUnsafeIP(ip net.IP) bool {
	return ip.IsLoopback() ||
		ip.IsLinkLocalUnicast() ||
		ip.IsLinkLocalMulticast() ||
		ip.IsPrivate() ||
		ip.IsUnspecified() ||
		ip.IsMulticast()
}

// ConfigureWebhook handles POST requests to configure a webhook URL.
// It validates the URL to prevent SSRF and DNS Rebinding attacks.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format and ensure it is absolute
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil || parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// SSRF Prevention: Create a custom dialer that validates the resolved IP.
	// This is the most effective way to prevent DNS Rebinding.
	dialer := &net.Dialer{
		Timeout: 3 * time.Second,
		Control: func(network, address string, c syscall.RawConn) error {
			host, _, err := net.SplitHostPort(address)
			if err != nil {
				return err
			}
			ip := net.ParseIP(host)
			if ip != nil && isUnsafeIP(ip) {
				return fmt.Errorf("connection to private or local network is prohibited")
			}
			return nil
		},
	}

	// Create a custom HTTP client
	client := &http.Client{
		Timeout: 5 * time.Second,
		Transport: &http.Transport{
			DialContext:           dialer.DialContext,
			DisableKeepAlives:     true, // Recommended for one-off validation requests
			ResponseHeaderTimeout: 3 * time.Second,
		},
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// SSRF Prevention: Do not follow redirects.
			// This prevents an attacker from redirecting a "safe" URL to an internal one.
			return http.ErrUseLastResponse
		},
	}

	// Send test request to webhook URL using GET method as required
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration (Assume db is a predefined database instance)
	// db.SaveWebhookURL(req.WebhookURL)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

