// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// isSafeIP checks if an IP address is public and safe for outgoing requests
func isSafeIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsPrivate() || ip.IsUnspecified() {
		return false
	}
	return true
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// 1. Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// 2. Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// 3. Validate URL format and scheme
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// 4. SSRF Protection: Create a custom transport that validates IPs
	// This prevents access to internal networks and protects against DNS Rebinding.
	transport := &http.Transport{
		DialContext: func(c context.Context, network, addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			// Resolve IPs for the given host
			ips, err := net.DefaultResolver.LookupIP(c, "ip", host)
			if err != nil {
				return nil, err
			}

			var targetIP net.IP
			for _, ip := range ips {
				if isSafeIP(ip) {
					targetIP = ip
					break
				}
			}

			if targetIP == nil {
				return nil, errors.New("access to internal or private network addresses is prohibited")
			}

			// Dial the specific safe IP to prevent DNS Rebinding
			dialer := &net.Dialer{Timeout: 3 * time.Second}
			return dialer.DialContext(c, network, net.JoinHostPort(targetIP.String(), port))
		},
	}

	client := &http.Client{
		Transport: transport,
		Timeout:   5 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Do not follow redirects to prevent SSRF bypass via 3xx responses
			return http.ErrUseLastResponse
		},
	}

	// 5. Send test request to webhook URL using GET method as required
	testReq, err := http.NewRequestWithContext(ctx.Context(), "GET", req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to initialize test request",
		})
	}

	resp, err := client.Do(testReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook validation failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// 6. Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

