// isSafeIP checks if an IP address is public and safe to request.
// It blocks loopback, link-local, private, and unspecified (0.0.0.0) addresses.
func isSafeIP(ip net.IP) bool {
	// IsPrivate covers RFC 1918 (IPv4) and RFC 4193 (IPv6)
	return !(ip.IsLoopback() || 
		ip.IsLinkLocalUnicast() || 
		ip.IsLinkLocalMulticast() || 
		ip.IsPrivate() || 
		ip.IsUnspecified())
}

// ConfigureWebhook handles POST requests to configure a webhook URL.
// It validates the URL by sending a GET request while protecting against SSRF.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

