package main

import (
	"fmt"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest defines the expected JSON body for the configuration request
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the POST request to set up a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	// Parse JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid JSON body",
		})
	}

	// Basic validation
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout requirement
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Validate the webhook URL by sending a GET request
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
			"status":  "error",
			"message": fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the endpoint is reachable (accepting any 2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
			"status":  "error",
			"message": fmt.Sprintf("Webhook URL returned non-success status code: %d", resp.StatusCode),
		})
	}

	// Logic to save the configuration would go here (e.g., database update)
	// For this implementation, we assume success after validation.

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configuration saved and validated",
		"data": fiber.Map{
			"webhook_url": req.WebhookURL,
		},
	})
}

func main() {
	app := fiber.New()

	// Route definition
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server
	fmt.Println("Server starting on :3000...")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

