)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// isPrivateIP checks if an IP address belongs to a private, loopback, 
// link-local, or unspecified range to prevent SSRF.
func isPrivateIP(ip net.IP) bool {
	return ip.IsLoopback() || 
		ip.IsLinkLocalUnicast() || 
		ip.IsLinkLocalMulticast() || 
		ip.IsUnspecified() || 
		ip.IsPrivate()
}

// ConfigureWebhook handles POST requests to configure a webhook URL.
// It validates the URL by sending a GET request and ensures SSRF protection.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// 1. Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// 2. Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// 3. Validate URL format and scheme
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// 4. SSRF Mitigation: Preliminary check if the hostname is a literal private IP
	host := parsedURL.Hostname()
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
				"success": false,
				"error":   "Webhook URL points to a prohibited internal IP address",
			})
		}
	}

	// 5. SSRF Mitigation: Custom dialer with DNS Rebinding protection.
	// The Control function is called after DNS resolution but before the connection is made.
	dialer := &net.Dialer{
		Timeout: 3 * time.Second,
		Control: func(network, address string, c syscall.RawConn) error {
			host, _, err := net.SplitHostPort(address)
			if err != nil {
				return err
			}
			ip := net.ParseIP(host)
			if ip != nil && isPrivateIP(ip) {
				return fmt.Errorf("connection to prohibited IP address: %s", ip)
			}
			return nil
		},
	}

	// 6. Configure the HTTP client
	client := &http.Client{
		Timeout: 5 * time.Second,
		Transport: &http.Transport{
			DialContext:           dialer.DialContext,
			ForceAttemptHTTP2:     true,
			TLSHandshakeTimeout:   3 * time.Second,
			ExpectContinueTimeout: 1 * time.Second,
		},
		// SSRF Mitigation: Do not follow redirects to prevent bypasses via 3xx responses
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// 7. Send test request to webhook URL using GET method
	reqObj, err := http.NewRequestWithContext(ctx.UserContext(), http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}

	resp, err := client.Do(reqObj)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL (connection refused or prohibited)",
		})
	}
	defer resp.Body.Close()

	// 8. Check if the webhook responded with a success status (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

