package main

import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest defines the expected JSON body for the configuration request
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse defines the structure of the JSON response
type WebhookResponse struct {
	Status  string `json:"status"`
	Message string `json:"message"`
	URL     string `json:"url,omitempty"`
}

// ConfigureWebhook handles the POST request to set up and validate a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	req := new(WebhookRequest)

	// Parse JSON body
	if err := ctx.BodyParser(req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Status:  "error",
			Message: "Invalid JSON body",
		})
	}

	// Basic validation of input
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Status:  "error",
			Message: "webhook_url field is required",
		})
	}

	// Create an HTTP client with a 3-second timeout requirement
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Validate the webhook URL by sending a GET request
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(WebhookResponse{
			Status:  "error",
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(WebhookResponse{
			Status:  "error",
			Message: "Webhook URL returned a non-success status code",
		})
	}

	// At this point, the URL is validated.
	// In a real application, you would save req.WebhookURL to your database here.

	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Status:  "success",
		Message: "Webhook configured and validated successfully",
		URL:     req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Route definition
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server
	err := app.Listen(":3000")
	if err != nil {
		panic(err)
	}
}

