)

// WebhookRequest defines the structure for the incoming JSON body
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// Response defines the structure for the JSON response
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles the POST request to set up a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	// Parse JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Basic validation
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate the webhook URL by sending a GET request with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Failed to reach webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the response status is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned non-success status code: %d", resp.StatusCode),
		})
	}

	// In a real application, you would save the webhook_url to a database here.
	fmt.Printf("Successfully configured webhook URL: %s\n", req.WebhookURL)

	return ctx.Status(fiber.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configuration saved and validated successfully",
	})
}

func main() {
	app := fiber.New()

	// Route configuration
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server
	fmt.Println("Server starting on :3000...")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

